code.C:
#include <stdio.h>
#include <stdbool.h>
bool isUniqueBT(int* inorder, int inorderSize) {
    for (int i = 0; i < inorderSize - 1; i++) {
        if (inorder[i] == inorder[i + 1]) {
            return false;
        }
    }
    return true;
}
int main() {
    int inorder[] = {1, 2, 3};
    int inorderSize = sizeof(inorder) / sizeof(inorder[0]);
    printf("%d\n", isUniqueBT(inorder, inorderSize));
    return 0;
}

